import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Edge case: empty
  it("empty item list → premium 5 G (only the processing fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result).toEqual({ results: [{ premium: 5 }] });
  });

  // Base premiums per item type (with fee)
  it("single sword (plain, low enchantment) → 100 G base + 10 G first insurance + 5 G fee = 115 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", material: "steel", enchantment: 1, cursed: false }] }],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it.todo("single amulet (plain, low enchantment) → 60 G base + 6 G first insurance + 5 G fee = 71 G");
  it.todo("single staff (plain, low enchantment) → 80 G base + 8 G first insurance + 5 G fee = 93 G");
  it.todo("single potion (plain, low enchantment) → 40 G base + 4 G first insurance + 5 G fee = 49 G");

  // Component pricing and building blocks
  it.todo("2 runes → 50 G base premium (plus first-insurance and fee)");
  it.todo("3 runes → 60 G base premium (block applies)");
  it.todo("4 runes → 100 G base premium (no block — block requires exactly 3)");
  it.todo("7 runes → 175 G base premium (one block of 3 at 60 G + 4 singles at 25 G)");

  // Alike components clarification
  it.todo("2 runes + 1 moonstone → 75 G base premium (no block: different types)");
  it.todo("3 runes + 3 moonstones → 120 G base premium (two separate blocks)");

  // Individual modifiers
  it.todo("cursed sword adds 50% surcharge to that item's base premium");
  it.todo("highly enchanted item (enchantment ≥ 5) adds 30% surcharge to that item");
  it.todo("sword with exactly enchantment 5 → high-enchantment surcharge applies");
  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
  it.todo("sword with enchantment 5 and cursed → both surcharges apply");
  it.todo("long-standing customer (≥ 2 years) → 20% loyalty discount on policy base");
  it.todo("customer with exactly 2 years → loyalty discount applies");
  it.todo("first insurance → 10% initial assessment surcharge per item");
  it.todo("follow-up contract (second quote+) → 15% discount on policy base");

  // Modifier scope on multi-item policies
  it.todo("cursed sword + plain amulet → policy base 160 G + 50 G curse (item-scoped) → 210 G before fee");

  // Rounding
  it.todo("premium that yields 197.5 G rounds up to 198 G (MHPCO's favor)");
  it.todo("payout that yields 350.5 G rounds down to 350 G (MHPCO's favor)");

  // Integration examples
  it.todo("newcomer with cursed sword (steel, enchantment 3) → 165 G");
  it.todo("long-standing customer's second contract with cursed sword (enchantment 7) → 160 G");

  // Claims — standard reimbursement
  it.todo("regular sword (steel, enchantment 3) damage 500 G → payout 400 G");
  it.todo("rune damage 200 G → payout 100 G (no special clause)");

  // Claim — high enchantment
  it.todo("steel sword, enchantment 9, damage 1000 G → payout 400 G (50% then deductible)");

  // Claim — dragon material
  it.todo("dragon-material sword, enchantment 5, damage 800 G → payout 700 G (full minus deductible)");

  // Claim — both clauses: 50% rule wins
  it.todo("dragon-material sword, enchantment 9, damage 1000 G → payout 400 G (50% then deductible)");
  it.todo("dragon-material sword, enchantment 8, damage 1000 G → payout 400 G (high-enchantment wins at threshold)");

  // Multiple damages: deductible per event
  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 G (deductible once per item)");

  // Cap rules
  it.todo("sword + amulet policy → insurance sum 1600 G, cap 3200 G");
  it.todo("cursed sword → cap 2000 G (based on unmodified insurance value, not modified premium)");
  it.todo("sword + 3-rune block → insurance sum 1750 G (block discount affects premium only)");

  // Cap exhaustion across claims
  it.todo("sword (cap 2000); first claim 1500 → payout 1400, remainingCap 600");
  it.todo("sword (cap 2000); after first 1500 claim, second 1500 → payout 600, remainingCap 0");

  // Multiple items of same type
  it.todo("policy with two swords → insurance sum 2000 G, cap 4000 G");
  it.todo("dragon attack damages both swords (two entries) → each gets its own deductible");
  it.todo("more sword damages than insured swords → CLI exits non-zero, claim rejected");

  // Edge cases / errors
  it.todo("quote with unknown item type → CLI exits non-zero, error to stderr, no results");
  it.todo("claim references item not in policy → CLI exits non-zero, error to stderr");
  it.todo("claim with negative damage amount → CLI exits non-zero, error to stderr");

  // Sanity check that runScenario exists for tests to import
  it("module exports runScenario", () => {
    expect(typeof runScenario).toBe("function");
  });
});

