type Item = { type: string };
type Step = { op: "quote"; items: Item[] };
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE = 0.1;

const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
  sword: 100,
  amulet: 60,
};

const quoteItems = (items: Item[]): number => {
  if (items.length === 0) return PROCESSING_FEE;
  const base = items.reduce((sum, item) => sum + BASE_PREMIUM_BY_TYPE[item.type], 0);
  const withFirstInsurance = base * (1 + FIRST_INSURANCE_SURCHARGE);
  return withFirstInsurance + PROCESSING_FEE;
};

export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
  const results = scenario.steps.map((step) => ({
    premium: quoteItems(step.items),
  }));
  return { results };
};

