type Item = { type: string };
type Step = { op: "quote"; items: Item[] };
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE = 0.1;
const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_PRICE = 60;

const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

const COMPONENT_TYPES = new Set(["rune"]);

const basePremiumOf = (item: Item): number => BASE_PREMIUM_BY_TYPE[item.type];

const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);

const priceForComponentGroup = (type: string, count: number): number =>
  count === COMPONENT_BLOCK_SIZE
    ? COMPONENT_BLOCK_PRICE
    : count * BASE_PREMIUM_BY_TYPE[type];

const countByType = (items: Item[]): Map<string, number> => {
  const counts = new Map<string, number>();
  for (const item of items) {
    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
  }
  return counts;
};

const sumBasePremiumsFor = (items: Item[]): number => {
  const mainItemsTotal = items
    .filter((item) => !isComponent(item))
    .reduce((sum, item) => sum + basePremiumOf(item), 0);

  const componentsTotal = Array.from(countByType(items.filter(isComponent)))
    .reduce((sum, [type, count]) => sum + priceForComponentGroup(type, count), 0);

  return mainItemsTotal + componentsTotal;
};

const computePremium = (items: Item[]): number => {
  const base = sumBasePremiumsFor(items);
  const withFirstInsurance = base * (1 + FIRST_INSURANCE_SURCHARGE);
  return withFirstInsurance + PROCESSING_FEE;
};

// Rounds up to the nearest whole gold piece, in MHPCO's favor.
// Cleans float noise (e.g. 66.00000000000001) before ceiling.
const roundUpToGold = (amount: number): number =>
  Math.ceil(Math.round(amount * 1e6) / 1e6);

export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
  const results = scenario.steps.map((step) => ({
    premium: roundUpToGold(computePremium(step.items)),
  }));
  return { results };
};

