  POLICY_MODIFIER_RULES.reduce((rate, rule) => rate + (rule.applies(customer) ? rule.rate : 0), 0);

const computePremium = (items: Item[], customer: Customer): number => {
  const policyBase = sumBasePremiumsFor(items);
  const itemSurcharges = itemSurchargesFor(items);
  const policyModifiers = policyBase * policyModifierRateFor(customer);
  return policyBase + itemSurcharges + policyModifiers + PROCESSING_FEE;
};

// Rounds up to the nearest whole gold piece, in MHPCO's favor.
// Cleans float noise (e.g. 66.00000000000001) before ceiling.
const roundUpToGold = (amount: number): number =>
  Math.ceil(Math.round(amount * 1e6) / 1e6);

export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
  const results = scenario.steps.map((step) => ({
    premium: roundUpToGold(computePremium(step.items)),
  }));
  return { results };
};

