input.new_string:
type Policy = { items: Item[]; cap: number; remainingCap: number };

const insuranceSumFor = (items: Item[]): number =>
  items.reduce((sum, item) => sum + INSURANCE_VALUE_BY_TYPE[item.type], 0);

const roundDownToGold = (amount: number): number =>
  Math.floor(Math.round(amount * 1e6) / 1e6);

const payoutForDamage = (damage: Damage): number =>
  Math.max(0, damage.amount - DEDUCTIBLE_PER_DAMAGE);

const processClaim = (step: ClaimStep, policies: Policy[]): ClaimResult => {
  const policy = policies[step.policy];
  const grossPayout = step.incident.damages.reduce((sum, d) => sum + payoutForDamage(d), 0);
  const cappedPayout = Math.min(grossPayout, policy.remainingCap);
  const payout = roundDownToGold(cappedPayout);
  policy.remainingCap -= payout;
  return { payout, remainingCap: policy.remainingCap };
};

export const runScenario = (scenario: Scenario): { results: StepResult[] } => {
  const policies: Policy[] = [];
  let quoteIndex = 0;
  const results: StepResult[] = scenario.steps.map((step) => {
    if (step.op === "quote") {
      const ctx: PolicyContext = { customer: scenario.customer, quoteIndex };
      quoteIndex += 1;
      const insuranceSum = insuranceSumFor(step.items);
      const cap = insuranceSum * CAP_MULTIPLIER;
      policies.push({ items: step.items, cap, remainingCap: cap });
      return { premium: roundUpToGold(computePremium(step.items, ctx)) };
    }
    return processClaim(step, policies);
  });
  return { results };
};

